-                defer allocator.free(ids);
-
-                var groups = std.AutoHashMap(i64, f64).init(allocator);
-                defer groups.deinit();
-
-                for (ids, 0..) |id, i| {
-                    const entry = groups.getOrPutValue(id, 0) catch break;
-                    entry.value_ptr.* += amounts[i];
-                }
-                std.mem.doNotOptimizeAway(&groups);
-            },
-        }
-
-        iterations += 1;
