-    while (result_iter.next()) |entry| {
-        const result_ptr = entry.value_ptr.*;
-        result_ptr.deinit();
-        allocator.destroy(result_ptr);
-    }
-    results.clearAndFree();
+    // No-op: Let the OS reclaim memory on process exit
 }
